# Check what products S_1 orders on day 50
for fname in os.listdir('/app/raw_orders/'):
    if 'day_050_S_1' in fname:
        fpath = f'/app/raw_orders/{fname}'
        with open(fpath) as f:
            content = f.read()
        print(f'File: {fname}')
        print(content[:500])
        break

# How many distinct products does S_1 order on day 1?
for fname in os.listdir('/app/raw_orders/'):
    if 'day_001_S_1' in fname:
        fpath = f'/app/raw_orders/{fname}'
        with open(fpath) as f:
            content = f.read()
        print(f'\\nFile: {fname}')
        print(content[:1000])
        break

# Check supplier receipts for P_1 on day 50
print('\\n--- Suppliers delivering P_1 on day 50 ---')
count = 0
for fname in sorted(os.listdir('/app/raw_supplier_receipts/')):
    if not 'day_050' in fname:
        continue
    fpath = f'/app/raw_supplier_receipts/{fname}'
    with open(fpath) as f:
        content = f.read()
    if 'P_1' in content:
        m = re.match(r'day_(\d+)_(PR_\d+)_', fname)
        if m:
            # Extract qty
            if 'api-json' in fname:
                data = json.loads(content)
                for item in data.get('items', []):
                    if item['prod_id'] == 'P_1':
                        print(f'  {m.group(2)}: {item[\"delivered_qty\"]} units of P_1')
            elif 'key-value' in fname:
                for line in content.split('\\n'):
                    if 'P_1' in line and 'DELIVERED_QTY' in line:
                        print(f'  {m.group(2)}: {line.strip()}')
            elif 'text-template' in fname:
                for line in content.split('\\n'):
                    m2 = re.search(r'delivered (\d+) units of product P_1', line)
                    if m2:
                        print(f'  {m.group(2)}: {m2.group(1)} units of P_1')
            elif 'table-csv' in fname:
                for line in content.split('\\n'):
                    if line.startswith('P_1;'):
                        print(f'  {m.group(2)}: {line.strip()}')
            count += 1
print(f'Total suppliers delivering P_1 on day 50: {count}')
" 2>&1

