# Check order files for S_3 to see P_7 ordering frequency
p7_orders = []
for fname in sorted(os.listdir('/app/raw_orders/')):
    if '_S_3_' not in fname:
        continue
    fpath = f'/app/raw_orders/{fname}'
    m = re.match(r'day_(\d+)_S_3_(.+)', fname)
    if not m:
        continue
    day = int(m.group(1))
    fmt = m.group(2)
    with open(fpath) as f:
        content = f.read()

    qty = None
    if 'api-json' in fmt:
        import json
        data = json.loads(content)
        for item in data.get('items', []):
            if item['prod_id'] == 'P_7':
                qty = item['qty']
    elif 'key-value' in fmt:
        for line in content.split('\n'):
            if 'P_7' in line and 'ORDER_QTY' in line:
                m2 = re.search(r'ORDER_PRODUCT: P_7 \| ORDER_QTY: (\d+)', line)
                if m2:
                    qty = int(m2.group(1))
    elif 'text-template' in fmt:
        m2 = re.search(r'deliver (\d+) units of product P_7', content)
        if m2:
            qty = int(m2.group(1))
    elif 'table-csv' in fmt:
        for line in content.split('\n'):
            if line.startswith('P_7;'):
                qty = int(line.split(';')[1])

    if qty is not None:
        p7_orders.append((day, qty))

print(f'S_3 P_7 orders: {len(p7_orders)} days out of 365')
print('Sample (first 20):', p7_orders[:20])
print('Days with orders:', [d for d, q in p7_orders[:50]])
" 2>&1

