import os, re, json
from collections import defaultdict

# Identify which products each supplier delivers on day 1
sup_products = defaultdict(set)
for fname in sorted(os.listdir('/app/raw_supplier_receipts/')):
    if 'day_001' not in fname:
        continue
    fpath = f'/app/raw_supplier_receipts/{fname}'
    m = re.match(r'day_001_(PR_\d+)_(.+)', fname)
    if not m:
        continue
    supplier = m.group(1)
    fmt = m.group(2)
    with open(fpath) as f:
        content = f.read()

    prods = set()
    if 'api-json' in fmt:
        data = json.loads(content)
        for item in data.get('items', []):
            prods.add(item['prod_id'])
    elif 'key-value' in fmt:
        for m2 in re.finditer(r'PRODUCT: (P_\d+) \|', content):
            prods.add(m2.group(1))
    elif 'text-template' in fmt:
        for m2 in re.finditer(r'units of product (P_\d+)\.', content):
            prods.add(m2.group(1))
    elif 'table-csv' in fmt:
        for line in content.split('\n')[1:]:
            if ';' in line:
                prods.add(line.split(';')[0])

    sup_products[supplier] = prods

print('Suppliers and their products on Day 1:')
for sup in sorted(sup_products.keys()):
    print(f'  {sup}: {sorted(sup_products[sup])}')

# Product to supplier mapping
print()
prod_sups = defaultdict(set)
for sup, prods in sup_products.items():
    for p in prods:
        prod_sups[p].add(sup)

print('Products and suppliers on Day 1:')
for prod in sorted(prod_sups.keys()):
    print(f'  {prod}: {len(prod_sups[prod])} suppliers: {sorted(prod_sups[prod])}')
" 2>&1

