#!/usr/bin/env python3
"""Supply chain quality analysis - comprehensive FIFO trace."""

import os, json, re, csv
from collections import defaultdict
import pandas as pd
import numpy as np

print("=== LOADING DATA ===", flush=True)

# Parse supplier receipts
def parse_supplier_receipt(filepath):
    filename = os.path.basename(filepath)
    m = re.match(r'day_(\d+)_(PR_\d+)_(.+)', filename)
    if not m: return None
    day, supplier, fmt = int(m.group(1)), m.group(2), m.group(3)
    deliveries = {}
    try:
        with open(filepath) as f:
            content = f.read()
        if 'api-json' in fmt:
            data = json.loads(content)
            for item in data.get('items', []):
                deliveries[item['prod_id']] = item['delivered_qty']
        elif 'table-csv' in fmt:
            for line in content.strip().split('\n')[1:]:
                parts = line.strip().split(';')
                if len(parts) >= 2:
                    try: deliveries[parts[0]] = int(parts[1])
                    except: pass
        elif 'text-template' in fmt:
            for m2 in re.finditer(r'delivered (\d+) units of product (P_\d+)', content):
                deliveries[m2.group(2)] = int(m2.group(1))
        elif 'key-value' in fmt:
            for m2 in re.finditer(r'PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)', content):
                deliveries[m2.group(1)] = int(m2.group(2))
    except: pass
    return (day, supplier, deliveries)

def parse_order(filepath):
    filename = os.path.basename(filepath)
    m = re.match(r'day_(\d+)_(S_\d+)_(.+)', filename)
    if not m: return None
    day, store, fmt = int(m.group(1)), m.group(2), m.group(3)
    order = {}
    try:
        with open(filepath) as f:
            content = f.read()
        if 'api-json' in fmt:
            data = json.loads(content)
            for item in data.get('items', []):
                order[item['prod_id']] = item['qty']
        elif 'table-csv' in fmt:
            for line in content.strip().split('\n')[1:]:
                parts = line.strip().split(';')
                if len(parts) >= 2:
                    try: order[parts[0]] = int(parts[1])
                    except: pass
        elif 'text-template' in fmt:
            for m2 in re.finditer(r'deliver (\d+) units of product (P_\d+)', content):
                order[m2.group(2)] = int(m2.group(1))
        elif 'key-value' in fmt:
            for m2 in re.finditer(r'ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)', content):
                order[m2.group(1)] = int(m2.group(2))
    except: pass
    return (day, store, order)

print("  Parsing supplier receipts...", flush=True)
supplier_deliveries = {}
for fname in os.listdir('/app/raw_supplier_receipts/'):
    r = parse_supplier_receipt(f'/app/raw_supplier_receipts/{fname}')
    if r: supplier_deliveries[(r[0], r[1])] = r[2]

print("  Parsing wholesaler receipts...", flush=True)
wholesaler_seq = {}
for fname in os.listdir('/app/raw_wholesaler_receipts/'):
    m = re.match(r'day_(\d+)_(PR_\d+)_receipt\.txt', fname)
    if not m: continue
    day, sup = int(m.group(1)), m.group(2)
    with open(f'/app/raw_wholesaler_receipts/{fname}') as f:
        content = f.read()
    m2 = re.search(r'DAILY_SEQUENCE_NO: (\d+)', content)
    if m2: wholesaler_seq[(day, sup)] = int(m2.group(1))

print("  Parsing store receipts...", flush=True)
store_receipts = {}
for fname in os.listdir('/app/raw_wholesaler_store_receipts/'):
    m = re.match(r'day_(\d+)_(S_\d+)_receipt\.txt', fname)
    if not m: continue
    day, store = int(m.group(1)), m.group(2)
    with open(f'/app/raw_wholesaler_store_receipts/{fname}') as f:
        content = f.read()
    m2 = re.search(r'DAILY_SEQUENCE_NO: (\d+)', content)
    m3 = re.search(r'TOTAL_DELIVERED_UNITS: (\d+)', content)
    if m2 and m3: store_receipts[(day, store)] = (int(m2.group(1)), int(m3.group(1)))

print("  Parsing store orders...", flush=True)
store_orders = {}
for fname in os.listdir('/app/raw_orders/'):
    r = parse_order(f'/app/raw_orders/{fname}')
    if r: store_orders[(r[0], r[1])] = r[2]

print("  Loading sales log...", flush=True)
sales = pd.read_csv('/app/sales_log.csv')
daily_agg = sales.groupby(['Day', 'Store_ID', 'Product_ID'])['Sold_Quantity'].sum().reset_index()
daily_sold = {}
for _, row in daily_agg.iterrows():
    daily_sold[(int(row['Day']), row['Store_ID'], row['Product_ID'])] = row['Sold_Quantity']

print("  All data loaded.", flush=True)

DAYS = 365
ALL_SUPPLIERS = sorted(set(sup for (d, sup) in wholesaler_seq.keys()))
ALL_STORES = [f'S_{i}' for i in range(1, 11)]
ALL_PRODUCTS = sorted(set(p for d in supplier_deliveries.values() for p in d.keys()))
print(f"  Suppliers: {len(ALL_SUPPLIERS)}, Stores: {len(ALL_STORES)}, Products: {len(ALL_PRODUCTS)}", flush=True)

print("\n=== RECONSTRUCT STORE DELIVERIES ===", flush=True)

# store_daily_receipts[day][store][product] = [(supplier, qty), ...]
store_daily_receipts = defaultdict(lambda: defaultdict(lambda: defaultdict(list)))

for day in range(1, DAYS + 1):
    # Build wholesaler inventory per product, in supplier sequence order
    wholesaler_inv = defaultdict(list)

    day_sups = sorted(
        [(wholesaler_seq[(day, s)], s) for s in ALL_SUPPLIERS if (day, s) in wholesaler_seq]
    )
    for seq, sup in day_sups:
        if (day, sup) in supplier_deliveries:
            for prod, qty in supplier_deliveries[(day, sup)].items():
                if qty > 0:
                    wholesaler_inv[prod].append([sup, qty])

    # Serve stores in sequence order
    day_stores = sorted(
        [(store_receipts[(day, s)][0], s) for s in ALL_STORES if (day, s) in store_receipts]
    )
    for seq, store in day_stores:
        order = store_orders.get((day, store), {})
        for prod, qty_needed in order.items():
            if prod not in wholesaler_inv or not wholesaler_inv[prod]:
                continue
            remaining = qty_needed
            for batch in wholesaler_inv[prod]:
                if remaining <= 0: break
                take = min(remaining, batch[1])
                if take > 0:
                    store_daily_receipts[day][store][prod].append((batch[0], take))
                    batch[1] -= take
                    remaining -= take
            wholesaler_inv[prod] = [b for b in wholesaler_inv[prod] if b[1] > 0]

print("  Reconstruction complete.", flush=True)

# Build FIFO queues: store_fifo[store][product] = [(day, supplier, qty), ...]
store_fifo = defaultdict(lambda: defaultdict(list))
for day in range(1, DAYS + 1):
    for store in ALL_STORES:
        for prod in ALL_PRODUCTS:
            for sup, qty in store_daily_receipts[day][store][prod]:
                store_fifo[store][prod].append((day, sup, qty))

print("  FIFO queues built.", flush=True)

# Verify FIFO for S_3 P_7
fifo_s3p7 = store_fifo['S_3']['P_7']
print(f"  S_3 P_7 FIFO entries: {len(fifo_s3p7)}")
print(f"  First 5: {fifo_s3p7[:5]}")
print(f"  Unique delivery days: {len(set(d for d, s, q in fifo_s3p7))}")
print(f"  Total received: {sum(q for d, s, q in fifo_s3p7)}")

# Total sold at S_3 P_7
s3p7_sold = sum(v for (d, s, p), v in daily_sold.items() if s == 'S_3' and p == 'P_7')
print(f"  Total sold: {s3p7_sold}")

print("\n=== IDENTIFY DEMAND ANOMALIES ===", flush=True)

daily_demand_df = sales.groupby(['Day', 'Store_ID', 'Product_ID'])['Reported_Demand'].sum().reset_index()
daily_demand_dict = {}
for _, row in daily_demand_df.iterrows():
    daily_demand_dict[(int(row['Day']), row['Store_ID'], row['Product_ID'])] = row['Reported_Demand']

# For each (store, product), compute normalized demand ratio
all_anomalies = {}  # (store, product) -> list of anomaly_days with ratio

for product in ALL_PRODUCTS:
    pdata = {}
    for store in ALL_STORES:
        series = [daily_demand_dict.get((d, store, product), 0) for d in range(1, DAYS+1)]
        pdata[store] = np.array(series, dtype=float)

    for store in ALL_STORES:
        other_stores = [s for s in ALL_STORES if s != store]
        others_matrix = np.array([pdata[s] for s in other_stores])
        median_others = np.nanmedian(others_matrix, axis=0)

        # Where median_others > 0
        valid = median_others > 0
        store_arr = pdata[store]

        # Store's typical ratio to others
        ratios = np.where(valid, store_arr / median_others, np.nan)
        long_term_med = np.nanmedian(ratios)
        if long_term_med == 0 or np.isnan(long_term_med):
            continue

        expected = median_others * long_term_med
        norm_ratio = np.where(expected > 0, store_arr / expected, np.nan)

        anomaly_days = [(d+1, norm_ratio[d]) for d in range(DAYS)
                        if not np.isnan(norm_ratio[d]) and norm_ratio[d] < 0.85]

        if len(anomaly_days) >= 7:
            all_anomalies[(store, product)] = anomaly_days

print(f"  Found {len(all_anomalies)} (store, product) pairs with 7+ anomaly days", flush=True)

# Find anomaly run starts
def find_run_starts(anomaly_days):
    """Find the first day of each contiguous run (gap > 3 = new run)."""
    days = sorted(d for d, r in anomaly_days)
    if not days:
        return []
    starts = [days[0]]
    for i in range(1, len(days)):
        if days[i] - days[i-1] > 3:
            starts.append(days[i])
    return starts

print("\n=== FIFO TRACING ===", flush=True)

def get_active_supplier(store, product, target_day):
    """Return the set of (supplier, fraction) at front of FIFO on target_day."""
    fifo = store_fifo[store][product]
    if not fifo:
        return {}

    # Cumulative received up to target_day
    cum_received = []
    cum = 0
    for (rec_day, sup, qty) in fifo:
        if rec_day <= target_day:
            cum_received.append((cum, cum + qty, sup, rec_day))
            cum += qty

    if not cum_received:
        return {}

    # Cumulative sold before target_day (days 1 to target_day-1)
    cum_sold = sum(daily_sold.get((d, store, product), 0) for d in range(1, target_day))

    # Units sold ON target_day
    sold_today = daily_sold.get((target_day, store, product), 0)

    # The "front" consumption window: [cum_sold, cum_sold + sold_today)
    # Find which supplier's batch covers the cum_sold position
    consumed_start = cum_sold
    consumed_end = cum_sold + max(sold_today, 1)  # at least 1 to find current front

    active = {}
    for (bs, be, sup, rec_day) in cum_received:
        overlap_start = max(bs, consumed_start)
        overlap_end = min(be, consumed_end)
        if overlap_end > overlap_start:
            frac = (overlap_end - overlap_start) / max(consumed_end - consumed_start, 1)
            if sup not in active:
                active[sup] = 0
            active[sup] += frac

    return active

# For each anomaly, trace FIFO at run starts and the days before
confirmed = defaultdict(set)
candidate_events = []

top_pairs = sorted(all_anomalies.keys(),
                   key=lambda x: min(r for d, r in all_anomalies[x]))

for (store, product) in top_pairs:
    anomaly_days = all_anomalies[(store, product)]
    run_starts = find_run_starts(anomaly_days)
    min_ratio = min(r for d, r in anomaly_days)

    if min_ratio > 0.75:  # Only focus on strong anomalies
        continue

    print(f"\n{'='*60}", flush=True)
    print(f"Anomaly: {store} {product}, min_ratio={min_ratio:.3f}, runs={len(run_starts)}", flush=True)
    print(f"  Run starts: {run_starts[:10]}", flush=True)

    # For each run start, check who's at the front of FIFO
    # The quality rejection happens on day (start - 1) for consumers entering recovery on start day
    # But because multiple consumers receive bad batches over time, the run start is
    # when enough consumers have entered recovery that the aggregate drop becomes visible

    # Check days around the run start
