print(f"  S_3 P_7 FIFO entries: {len(fifo_s3p7)}")
print(f"  First 5: {fifo_s3p7[:5]}")
print(f"  Unique delivery days: {len(set(d for d, s, q in fifo_s3p7))}")
print(f"  Total received: {sum(q for d, s, q in fifo_s3p7)}")

# Total sold at S_3 P_7
