#!/usr/bin/env python3
"""Final comprehensive quality attribution analysis."""

import os, json, re
from collections import defaultdict
import pandas as pd
import numpy as np

print("Loading pre-built data structures...", flush=True)

# === Quick re-parse (leveraging already-verified approach) ===
def parse_supplier_receipt(filepath):
    filename = os.path.basename(filepath)
    m = re.match(r'day_(\d+)_(PR_\d+)_(.+)', filename)
    if not m: return None
    day, supplier, fmt = int(m.group(1)), m.group(2), m.group(3)
    deliveries = {}
    try:
        with open(filepath) as f: content = f.read()
        if 'api-json' in fmt:
            data = json.loads(content)
            for item in data.get('items', []): deliveries[item['prod_id']] = item['delivered_qty']
        elif 'table-csv' in fmt:
            for line in content.strip().split('\n')[1:]:
                parts = line.strip().split(';')
                if len(parts) >= 2:
                    try: deliveries[parts[0]] = int(parts[1])
                    except: pass
        elif 'text-template' in fmt:
            for m2 in re.finditer(r'delivered (\d+) units of product (P_\d+)', content):
                deliveries[m2.group(2)] = int(m2.group(1))
        elif 'key-value' in fmt:
            for m2 in re.finditer(r'PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)', content):
                deliveries[m2.group(1)] = int(m2.group(2))
    except: pass
    return (day, supplier, deliveries)

def parse_order(filepath):
    filename = os.path.basename(filepath)
    m = re.match(r'day_(\d+)_(S_\d+)_(.+)', filename)
    if not m: return None
    day, store, fmt = int(m.group(1)), m.group(2), m.group(3)
    order = {}
    try:
        with open(filepath) as f: content = f.read()
        if 'api-json' in fmt:
            data = json.loads(content)
            for item in data.get('items', []): order[item['prod_id']] = item['qty']
        elif 'table-csv' in fmt:
            for line in content.strip().split('\n')[1:]:
                parts = line.strip().split(';')
                if len(parts) >= 2:
                    try: order[parts[0]] = int(parts[1])
                    except: pass
        elif 'text-template' in fmt:
            for m2 in re.finditer(r'deliver (\d+) units of product (P_\d+)', content):
                order[m2.group(2)] = int(m2.group(1))
        elif 'key-value' in fmt:
            for m2 in re.finditer(r'ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)', content):
                order[m2.group(1)] = int(m2.group(2))
    except: pass
    return (day, store, order)

supplier_deliveries = {}
for fname in os.listdir('/app/raw_supplier_receipts/'):
    r = parse_supplier_receipt(f'/app/raw_supplier_receipts/{fname}')
    if r: supplier_deliveries[(r[0], r[1])] = r[2]

wholesaler_seq = {}
for fname in os.listdir('/app/raw_wholesaler_receipts/'):
    m = re.match(r'day_(\d+)_(PR_\d+)_receipt\.txt', fname)
    if not m: continue
    day, sup = int(m.group(1)), m.group(2)
    with open(f'/app/raw_wholesaler_receipts/{fname}') as f: content = f.read()
    m2 = re.search(r'DAILY_SEQUENCE_NO: (\d+)', content)
    if m2: wholesaler_seq[(day, sup)] = int(m2.group(1))

store_receipts = {}
for fname in os.listdir('/app/raw_wholesaler_store_receipts/'):
    m = re.match(r'day_(\d+)_(S_\d+)_receipt\.txt', fname)
    if not m: continue
    day, store = int(m.group(1)), m.group(2)
    with open(f'/app/raw_wholesaler_store_receipts/{fname}') as f: content = f.read()
    m2 = re.search(r'DAILY_SEQUENCE_NO: (\d+)', content)
    m3 = re.search(r'TOTAL_DELIVERED_UNITS: (\d+)', content)
    if m2 and m3: store_receipts[(day, store)] = (int(m2.group(1)), int(m3.group(1)))

store_orders = {}
for fname in os.listdir('/app/raw_orders/'):
    r = parse_order(f'/app/raw_orders/{fname}')
    if r: store_orders[(r[0], r[1])] = r[2]

sales = pd.read_csv('/app/sales_log.csv')
daily_sold = {}
for _, row in sales.groupby(['Day', 'Store_ID', 'Product_ID'])['Sold_Quantity'].sum().reset_index().iterrows():
    daily_sold[(int(row['Day']), row['Store_ID'], row['Product_ID'])] = row['Sold_Quantity']

print("All data loaded.", flush=True)

DAYS = 365
ALL_SUPPLIERS = sorted(set(sup for (d, sup) in wholesaler_seq.keys()))
ALL_STORES = [f'S_{i}' for i in range(1, 11)]

# Reconstruct store deliveries
store_daily_receipts = defaultdict(lambda: defaultdict(lambda: defaultdict(list)))
for day in range(1, DAYS + 1):
    wholesaler_inv = defaultdict(list)
    day_sups = sorted([(wholesaler_seq[(day, s)], s) for s in ALL_SUPPLIERS if (day, s) in wholesaler_seq])
    for seq, sup in day_sups:
        if (day, sup) in supplier_deliveries:
            for prod, qty in supplier_deliveries[(day, sup)].items():
                if qty > 0: wholesaler_inv[prod].append([sup, qty])
    day_stores = sorted([(store_receipts[(day, s)][0], s) for s in ALL_STORES if (day, s) in store_receipts])
