            remaining = qty_needed
            for batch in wholesaler_inv[prod]:
                if remaining <= 0: break
                take = min(remaining, batch[1])
                if take > 0:
                    store_daily_receipts[day][store][prod].append((batch[0], take))
                    batch[1] -= take
                    remaining -= take
            wholesaler_inv[prod] = [b for b in wholesaler_inv[prod] if b[1] > 0]

# Build FIFO
ALL_PRODUCTS = sorted(set(p for d in supplier_deliveries.values() for p in d.keys()))
store_fifo = defaultdict(lambda: defaultdict(list))
for day in range(1, DAYS + 1):
    for store in ALL_STORES:
        for prod in ALL_PRODUCTS:
            for sup, qty in store_daily_receipts[day][store][prod]:
                store_fifo[store][prod].append((day, sup, qty))

print("FIFO built.", flush=True)

# Compute cumulative solds for efficiency
cum_sold = {}  # (store, product) -> list of length DAYS+1, cum_sold[d] = total sold days 1..d
for store in ALL_STORES:
    for prod in ALL_PRODUCTS:
        arr = [0] * (DAYS + 2)
        for d in range(1, DAYS + 1):
            arr[d] = arr[d-1] + daily_sold.get((d, store, prod), 0)
        cum_sold[(store, prod)] = arr

def get_active_supplier_fraction(store, product, target_day):
    """Return {supplier: fraction_of_consumption} for target_day."""
    fifo = store_fifo[store][product]
    if not fifo: return {}

    cs_arr = cum_sold.get((store, product), [0] * (DAYS + 2))
    cum_sold_before = cs_arr[target_day - 1]
    sold_today = daily_sold.get((target_day, store, product), 0)
    if sold_today == 0: return {}

    # Build cumulative received up to target_day
    cum_rcv = []
    cum = 0
    for (rec_day, sup, qty) in fifo:
        if rec_day <= target_day:
            cum_rcv.append((cum, cum + qty, sup))
            cum += qty

    consumed_start = cum_sold_before
    consumed_end = cum_sold_before + sold_today

    active = {}
    for (bs, be, sup) in cum_rcv:
        overlap_start = max(bs, consumed_start)
        overlap_end = min(be, consumed_end)
        if overlap_end > overlap_start:
            frac = (overlap_end - overlap_start) / sold_today
            active[sup] = active.get(sup, 0) + frac
    return active

print("Computing demand anomalies...", flush=True)

daily_demand_df = sales.groupby(['Day', 'Store_ID', 'Product_ID'])['Reported_Demand'].sum().reset_index()
demand_dict = {}
for _, row in daily_demand_df.iterrows():
    demand_dict[(int(row['Day']), row['Store_ID'], row['Product_ID'])] = row['Reported_Demand']

# Compute anomaly days for each (store, product)
all_anomaly_days = {}
for product in ALL_PRODUCTS:
    pdata = {}
    for store in ALL_STORES:
        pdata[store] = np.array([demand_dict.get((d, store, product), 0) for d in range(1, DAYS+1)], dtype=float)

    for store in ALL_STORES:
        other = [s for s in ALL_STORES if s != store]
        med = np.nanmedian([pdata[s] for s in other], axis=0)
        valid = med > 0
        with np.errstate(divide='ignore', invalid='ignore'):
            ratios = np.where(valid, pdata[store] / med, np.nan)
        lt_med = np.nanmedian(ratios)
        if lt_med == 0 or np.isnan(lt_med): continue
        expected = med * lt_med
        with np.errstate(divide='ignore', invalid='ignore'):
            norm_ratio = np.where(expected > 0, pdata[store] / expected, np.nan)

        a_days = [d+1 for d in range(DAYS) if not np.isnan(norm_ratio[d]) and norm_ratio[d] < 0.85]
        if len(a_days) >= 5:
            min_r = float(np.nanmin(norm_ratio))
            all_anomaly_days[(store, product)] = (a_days, min_r)

print(f"Found {len(all_anomaly_days)} anomalous (store, product) pairs.", flush=True)

# For each anomalous pair, compute supplier enrichment
print("Computing supplier enrichment...", flush=True)

enrichment_results = {}

for (store, product), (a_days, min_r) in all_anomaly_days.items():
    if min_r > 0.80: continue  # Focus on stronger anomalies

    a_set = set(a_days)
    anomaly_sup = defaultdict(float)
    normal_sup = defaultdict(float)

    for day in range(1, DAYS + 1):
        active = get_active_supplier_fraction(store, product, day)
        if not active: continue
        if day in a_set:
            for sup, frac in active.items():
                anomaly_sup[sup] += frac
        else:
            for sup, frac in active.items():
                normal_sup[sup] += frac

    total_a = sum(anomaly_sup.values())
    total_n = sum(normal_sup.values())

    if total_a == 0 or total_n == 0: continue

    enrichment = {}
    all_sups = set(list(anomaly_sup.keys()) + list(normal_sup.keys()))
    for sup in all_sups:
        a_share = anomaly_sup.get(sup, 0) / total_a
        n_share = normal_sup.get(sup, 0) / max(total_n, 1)
        if a_share > 0.01 or n_share > 0.01:
            enr = a_share / max(n_share, 0.001)
            enrichment[sup] = (a_share, n_share, enr)

    enrichment_results[(store, product)] = (min_r, enrichment)

print(f"Computed enrichment for {len(enrichment_results)} pairs.", flush=True)

# Aggregate by product: for each product, find suppliers with strong enrichment
print("\n=== PRODUCT-LEVEL ENRICHMENT SUMMARY ===", flush=True)

product_evidence = defaultdict(list)  # product -> [(enrichment, supplier, store, anomaly_share, min_ratio)]

for (store, product), (min_r, enrichment) in enrichment_results.items():
    for sup, (a_share, n_share, enr) in enrichment.items():
        if enr > 1.5 and a_share > 0.03:
            product_evidence[product].append((enr, sup, store, a_share, min_r))

# Print summary per product
confirmed_by_product = defaultdict(set)

print("\nAll products with strong supplier enrichment:", flush=True)
for product in sorted(ALL_PRODUCTS):
    evid = sorted(product_evidence.get(product, []), reverse=True)
    if not evid:
        continue
    print(f"\n{product}:", flush=True)

    # Group by supplier across stores
    sup_evidence = defaultdict(list)
    for enr, sup, store, a_share, min_r in evid:
        sup_evidence[sup].append((enr, store, a_share, min_r))

    # Sort suppliers by max enrichment
    sup_sorted = sorted(sup_evidence.items(), key=lambda x: -max(e[0] for e in x[1]))

    for sup, evidence_list in sup_sorted[:8]:
        max_enr = max(e[0] for e in evidence_list)
        max_share = max(e[2] for e in evidence_list)
        stores = [e[1] for e in evidence_list]
        min_ratios = [e[3] for e in evidence_list]
        print(f"  {sup}: max_enr={max_enr:.2f}, max_share={max_share:.3f}, stores={stores}, min_r={[round(x,3) for x in min_ratios]}", flush=True)

        # Confirm if strong signal
        if max_enr >= 3.0 and max_share >= 0.05 and min(min_ratios) < 0.75:
            confirmed_by_product[product].add(sup)
            print(f"    *** CONFIRMED ***", flush=True)

# Additional check: cross-product supplier pattern
print("\n=== CROSS-PRODUCT SUPPLIER ANALYSIS ===", flush=True)
sup_product_confirmed = defaultdict(set)
for prod, sups in confirmed_by_product.items():
    for sup in sups:
        sup_product_confirmed[sup].add(prod)

print("Confirmed suppliers and their products:", flush=True)
for sup in sorted(sup_product_confirmed.keys()):
    print(f"  {sup}: {sorted(sup_product_confirmed[sup])}", flush=True)

# Final result
print("\n=== FINAL ANSWER ===", flush=True)
result = {}
for product in sorted(ALL_PRODUCTS):
    sups = sorted(confirmed_by_product.get(product, set()))
    result[product] = sups
    if sups:
        print(f"  {product}: {sups}", flush=True)

with open('/tmp/result_v3.json', 'w') as f:
    json.dump(result, f, indent=2)
print("\nSaved to /tmp/result_v3.json", flush=True)
print(json.dumps(result), flush=True)

