cum_sold = {}  # (store, product) -> list of length DAYS+1, cum_sold[d] = total sold days 1..d
for store in ALL_STORES:
    for prod in ALL_PRODUCTS:
        arr = [0] * (DAYS + 2)
        for d in range(1, DAYS + 1):
            arr[d] = arr[d-1] + daily_sold.get((d, store, prod), 0)
        cum_sold[(store, prod)] = arr

def get_active_supplier_fraction(store, product, target_day):
    """Return {supplier: fraction_of_consumption} for target_day."""
    fifo = store_fifo[store][product]
    if not fifo: return {}

    cs_arr = cum_sold.get((store, product), [0] * (DAYS + 2))
    cum_sold_before = cs_arr[target_day - 1]
    sold_today = daily_sold.get((target_day, store, product), 0)
    if sold_today == 0: return {}

    # Build cumulative received up to target_day
    cum_rcv = []
    cum = 0
    for (rec_day, sup, qty) in fifo:
        if rec_day <= target_day:
            cum_rcv.append((cum, cum + qty, sup))
            cum += qty

    consumed_start = cum_sold_before
    consumed_end = cum_sold_before + sold_today

    active = {}
    for (bs, be, sup) in cum_rcv:
        overlap_start = max(bs, consumed_start)
        overlap_end = min(be, consumed_end)
        if overlap_end > overlap_start:
            frac = (overlap_end - overlap_start) / sold_today
            active[sup] = active.get(sup, 0) + frac
    return active

print("Computing demand anomalies...", flush=True)

daily_demand_df = sales.groupby(['Day', 'Store_ID', 'Product_ID'])['Reported_Demand'].sum().reset_index()
demand_dict = {}
for _, row in daily_demand_df.iterrows():
    demand_dict[(int(row['Day']), row['Store_ID'], row['Product_ID'])] = row['Reported_Demand']

# Compute anomaly days for each (store, product)
all_anomaly_days = {}
for product in ALL_PRODUCTS:
    pdata = {}
    for store in ALL_STORES:
        pdata[store] = np.array([demand_dict.get((d, store, product), 0) for d in range(1, DAYS+1)], dtype=float)

    for store in ALL_STORES:
        other = [s for s in ALL_STORES if s != store]
        med = np.nanmedian([pdata[s] for s in other], axis=0)
        valid = med > 0
        with np.errstate(divide='ignore', invalid='ignore'):
            ratios = np.where(valid, pdata[store] / med, np.nan)
        lt_med = np.nanmedian(ratios)
        if lt_med == 0 or np.isnan(lt_med): continue
        expected = med * lt_med
        with np.errstate(divide='ignore', invalid='ignore'):
            norm_ratio = np.where(expected > 0, pdata[store] / expected, np.nan)

        a_days = [d+1 for d in range(DAYS) if not np.isnan(norm_ratio[d]) and norm_ratio[d] < 0.85]
        if len(a_days) >= 5:
