        if a_share > 0.01 or n_share > 0.01:
            enr = a_share / max(n_share, 0.001)
            enrichment[sup] = (a_share, n_share, enr)

    enrichment_results[(store, product)] = (min_r, enrichment)

print(f"Computed enrichment for {len(enrichment_results)} pairs.", flush=True)

# Aggregate by product: for each product, find suppliers with strong enrichment
print("\n=== PRODUCT-LEVEL ENRICHMENT SUMMARY ===", flush=True)

product_evidence = defaultdict(list)  # product -> [(enrichment, supplier, store, anomaly_share, min_ratio)]

for (store, product), (min_r, enrichment) in enrichment_results.items():
